    operator_name    varchar(50)  null comment '操作人姓名',
    operate_time     datetime     null comment '操作时间',
    creater_id       varchar(36)  null comment '创建人id',
    create_time      datetime     null comment '创建时间',
    submit_time      datetime     null comment '提交时间',
    ext1             varchar(36)  null comment '修改内容是否已全部同步',
    ext2             varchar(36)  null comment '扩展字段2',
    ext3             varchar(36)  null comment '是否暂存',
    ext4             varchar(500) null comment '退回原因',
    is_collect_info  varchar(1)   null comment '是否收集信息提交的',
    approve_id       varchar(36)  null comment '审核人id',
    approve_name     varchar(50)  null comment '审批人姓名',
    approve_time     datetime     null comment '审批时间',
    property_page_id varchar(120) null comment '属性页id',
    post_data        mediumtext   null comment '提交的表单数据'
);

create table encrypt.hr_staff_selfhelp_task
(
    id              varchar(36)   null,
    selfhelp_num    varchar(36)   null comment '自助修改编号(用于区分修改批次)',
    participant_id  varchar(36)   null comment '参与者：人员、角色',
    config_id       varchar(36)   null comment '关联hr_staff_selfhelp_config.id，记录该任务在第几步',
    state           varchar(30)   null comment 'RUNNING(审批中),COMPLETE(审批完成)，BACK(退回)',
    operator        varchar(80)   null comment '操作人',
    operate_time    datetime      null comment '操作时间',
    approve_content mediumtext    null comment '审核内容',
    step            int           null comment '步骤（1,2,3....）',
    step_name       varchar(255)  null comment '步骤名称',
    modules         varchar(1000) null comment '审批模块',
    approve_module  varchar(1000) null comment '已审批模块'
);

create table encrypt.hr_staff_selfhelp_config
(
    id                   varchar(36)   null,
    root_id              varchar(36)   null comment '根组织ID',
    step                 int           null comment '步骤（1,2,3....）',
    step_name            varchar(255)  null comment '步骤名称',
    config_type          varchar(20)   null comment '审批分类(1,角色，2.人员)',
    config_value         varchar(36)   null comment '审批分类值',
    config_value_name    varchar(80)   null comment '审批分类值名称',
    operate_time         datetime      null comment '操作时间',
    staff_condition      mediumtext    null comment '适用人员条件，json',
    staff_condition_name mediumtext    null comment '适用人员条件，中文描述',
    staff_condition_sql  mediumtext    null comment '适用人员条件，sql语句',
    modules              varchar(1000) null comment '审批模块'
);
